class Calculator:
    def add(self, a, b):
        return a + b

    def subtract(self, a, b):
        return a - b

    def multiply(self, a, b):
        return a * b

    def divide(self, a, b):
        if b == 0:
            raise ZeroDivisionError("Cannot divide by zero")
        return a / b

    def logarithm(self, base, number):
        if base <= 0 or base == 1:
            raise ValueError("Invalid base for logarithm")
        if number <= 0:
            raise ValueError("Invalid number for logarithm")
        return math.log(number) / math.log(base)

    def factorial(self, n):
        if n < 0:
            raise ValueError("Factorial is not defined for negative numbers")
        if n == 0 or n == 1:
            return 1
        else:
            return n * self.factorial(n-1)

    def sine(self, angle):
        return math.sin(math.radians(angle))

    def cosine(self, angle):
        return math.cos(math.radians(angle))

    def tangent(self, angle):
        return math.tan(math.radians(angle))

    def square_root(self, number):
        if number < 0:
            raise ValueError("Square root of negative number is not a real number")
        return math.sqrt(number)

    def exponent(self, base, power):
        return base ** power

    def cube_root(self, number):
        return round(number ** (1/3), 3)

    def power_root(self, number, root):
        if root <= 0:
            raise ValueError("Root must be a positive number")
        if number < 0 and root % 2 == 0:
            raise ValueError("Even root of negative number is not a real number")
        return round(number ** (1/root), 3)

